import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"爱人吻","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/爱人吻.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/爱人吻.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/爱人吻.md"};function l(_,a,i,b,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"爱人吻",tabindex:"-1"},[s("爱人吻 "),e("a",{class:"header-anchor",href:"#爱人吻","aria-label":'Permalink to "爱人吻"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),o('<h1 id="爱人吻-1" tabindex="-1">爱人吻 <a class="header-anchor" href="#爱人吻-1" aria-label="Permalink to &quot;爱人吻&quot;">​</a></h1><p>爱人吻<br> C+1000<br> 特异本质<br> 描述：在锁骨处落下一吻，<br> 代替眼泪，道一句离别，<br> 白色的花朵为你铸造丰碑，<br> 你说过玫瑰很美，<br> 他们的血将如你所愿。<br> 这是具有11L，【高速5】【连射】【无限子弹】，射程为30米的，外观精致的两把改装版M1911手枪。枪身整体呈现暗红色，使用了玫瑰金镀层，抛壳窗则采用镀金边的银白色，左枪的握把部分雕刻着一朵艳丽的红玫瑰，右枪则连着枪身一起纹着一株曼珠沙华。<br> 这是一对双枪，故你必须同时持握两把手枪才能应用该武器的效果，占据双手位置，可以满足双持条件，但仅视为一把武器。<br> 该武器不会造成物理伤害，射出的子弹将在击中敌人的身躯后绽放出红色的花瓣，伤害转化为等量的魅惑点数，在判断来源时视为创伤。<br> 落花无心，流水无情，当持握这对武器时，你不会被C级及以下混乱效果所影响。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
